<!--  -->
<template>
  <div>
    <div class="f-table">
      <e-table
        :list-data="data"
        :headers="tableHeaders"
        :span-method="spanMethod"
      >
        <el-table-column
          width="40px"
          label="生时"
          type="index"
          :index="setIndex"
          slot="time"
        ></el-table-column>
      </e-table>
      <p class="title">安命宫及身宫表</p>
    </div>
  </div>
</template>

<script>
import tableHeaders from "./anMingGongJiShenGong.js";
import ETable from "@/components/ETable.vue";
import { tableData } from "@/utils/dataBuild.js";
export default {
  components: { ETable },
  data() {
    return {
      tableHeaders: tableHeaders,
      data: [],
      dizhi12: null,
    };
  },

  computed: {},
  created() {
    this.dizhi12 = new Map([
      [0, "子"],
      [1, "丑"],
      [3, "寅"],
      [5, "卯"],
      [7, "辰"],
      [9, "巳"],
      [11, "午"],
      [12, "未"],
      [14, "申"],
      [16, "酉"],
      [18, "戍"],
      [20, "亥"],
    ]);
    this.data = tableData.anMingGongJiShenGong;
  },
  mounted() {},

  methods: {
    // 设置行索引
    setIndex(index) {
      console.log("index :>> ", index);
      return this.dizhi12.get(index);
    },
    // 行合并方法
    spanMethod({ rowIndex, columnIndex }) {
      if (columnIndex === 0) {
        if (![0, 11].includes(rowIndex)) {
          if ([1, 3, 5, 7, 9, 12, 14, 16, 18, 20].includes(rowIndex)) {
            return {
              rowspan: 2,
              colspan: 1,
            };
          } else {
            return {
              rowspan: 0,
              colspan: 0,
            };
          }
        } else {
          return {
            rowspan: 1,
            colspan: 1,
          };
        }
      }
    },
  },
};
</script>
<style lang="scss" scoped>
.f-table {
  width: fit-content;
  text-align: center;
  .title {
    margin: 20px;
  }
}
</style>
